import{_ as t,c as a,o,a1 as n}from"./chunks/framework.DDNAyvCW.js";const r="/assets/host_conn.BwvazJ1c.png",m=JSON.parse('{"title":"Connect to a Host","description":"","frontmatter":{},"headers":[],"relativePath":"docs/hosts/connect.md","filePath":"docs/hosts/connect.md"}'),s={name:"docs/hosts/connect.md"};function i(l,e,h,c,d,u){return o(),a("div",null,e[0]||(e[0]=[n('<h1 id="connect-to-a-host" tabindex="-1">Connect to a Host <a class="header-anchor" href="#connect-to-a-host" aria-label="Permalink to &quot;Connect to a Host&quot;">​</a></h1><p>Once a host has been added to Chaterm, you can open an SSH session to it with a single click.</p><p><img src="'+r+'" alt=""></p><h2 id="how-to-connect" tabindex="-1">How to Connect <a class="header-anchor" href="#how-to-connect" aria-label="Permalink to &quot;How to Connect&quot;">​</a></h2><ol><li>Open the <strong>Host Management</strong> page from the left sidebar, or locate the host in the workspace.</li><li>Click the target host entry in the host list.</li><li>Chaterm establishes an SSH connection and opens a terminal window for the session.</li></ol><h2 id="troubleshooting-a-failed-connection" tabindex="-1">Troubleshooting a Failed Connection <a class="header-anchor" href="#troubleshooting-a-failed-connection" aria-label="Permalink to &quot;Troubleshooting a Failed Connection&quot;">​</a></h2><p>If the connection fails or drops unexpectedly, try the following steps:</p><ol><li><strong>Verify network reachability</strong> -- make sure your machine can reach the host. Try pinging the host IP address from your local terminal.</li><li><strong>Check credentials</strong> -- confirm that the username, password, or SSH key is correct. You can update credentials by editing the host entry (see <a href="/docs/hosts/edit-clone-delete">Edit, Clone &amp; Delete</a>).</li><li><strong>Confirm the SSH service is running</strong> -- ensure that the SSH daemon (e.g. <code>sshd</code>) is running on the target host and listening on the configured port.</li><li><strong>Check the port number</strong> -- the default SSH port is <code>22</code>. If your server uses a different port, make sure the host entry in Chaterm matches.</li><li><strong>Review firewall rules</strong> -- a firewall on the server or network may be blocking the SSH port. Verify that inbound traffic on the SSH port is allowed.</li><li><strong>Inspect the SSH proxy</strong> -- if you configured an SSH proxy, ensure the proxy server itself is reachable and properly configured.</li><li><strong>Rotate or re-import keys</strong> -- if you are using key authentication and the key was recently changed on the server, update or re-import the key in <a href="/docs/manage/keys/">Key Management</a>.</li></ol><h2 id="terminal-features" tabindex="-1">Terminal Features <a class="header-anchor" href="#terminal-features" aria-label="Permalink to &quot;Terminal Features&quot;">​</a></h2><p>After connecting, the terminal window provides several productivity features:</p><h3 id="multiple-tabs" tabindex="-1">Multiple Tabs <a class="header-anchor" href="#multiple-tabs" aria-label="Permalink to &quot;Multiple Tabs&quot;">​</a></h3><p>Open connections to multiple hosts at the same time. Each connection opens in its own tab at the top of the terminal area. Click a tab to switch between sessions, or use keyboard shortcuts to cycle through them.</p><h3 id="split-panes" tabindex="-1">Split Panes <a class="header-anchor" href="#split-panes" aria-label="Permalink to &quot;Split Panes&quot;">​</a></h3><p>Split the terminal area horizontally or vertically to view multiple sessions side by side. This is useful when you need to compare output from different servers or run commands on one host while monitoring another.</p><h3 id="context-menu" tabindex="-1">Context Menu <a class="header-anchor" href="#context-menu" aria-label="Permalink to &quot;Context Menu&quot;">​</a></h3><p>Right-click a terminal tab to access quick actions:</p><ul><li><strong>Close</strong> the current tab.</li><li><strong>Rename</strong> the tab for easier identification.</li><li><strong>Clone</strong> the session to open a duplicate connection in a new tab.</li><li>Other actions depending on context.</li></ul><h3 id="terminal-search" tabindex="-1">Terminal Search <a class="header-anchor" href="#terminal-search" aria-label="Permalink to &quot;Terminal Search&quot;">​</a></h3><p>Use the keyboard shortcut or the menu to open the search panel within the terminal. This lets you search through the terminal output history to find specific commands, log entries, or text.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="/docs/terminal/operations/">Terminal Operations</a> -- learn about advanced terminal features such as snippets, autocomplete, and AI-assisted commands.</li><li><a href="/docs/hosts/add-personal">Add a Personal Host</a> -- add a new server to your host list.</li><li><a href="/docs/hosts/add-bastion">Add a Bastion Host</a> -- add an enterprise bastion/jump server.</li><li><a href="/docs/hosts/add-router">Add a Router</a> -- add a network device.</li><li><a href="/docs/manage/keys/">Key Management</a> -- manage SSH keys used for authentication.</li></ul>',21)]))}const f=t(s,[["render",i]]);export{m as __pageData,f as default};
